var lat = parseFloat(msg.payload.latitude);
var lon = parseFloat(msg.payload.longitude);
var alt = msg.payload.altitude;
var vel = msg.payload.velocity;
var vis = msg.payload.visibility;

var iconColor = vis === "daylight" ? "#FF8C00" : "#808080";
var trailColor = vis === "daylight" ? "#FFD700" : "#aaaaaa";

var msgMap = {
    payload: {
        name: "ISS",
        lat: lat,
        lon: lon,
        icon: "satellite",
        iconColor: iconColor, 
        layer: "ISS Layer",
        trail: 500, 
        color: trailColor, 
        zoom: 3,
        command: { lat: lat, lon: lon }
    }
};

var msgVel = { payload: Math.round(vel), topic: "Velocity" };
var msgAlt = { payload: Math.round(alt), topic: "Altitude" };

var targetLat = 24.1632;
var targetLon = 120.6402;
function getDistanceFromLatLonInKm(lat1, lon1, lat2, lon2) {
  var R = 6371; 
  var dLat = deg2rad(lat2-lat1);  
  var dLon = deg2rad(lon2-lon1); 
  var a = 
    Math.sin(dLat/2) * Math.sin(dLat/2) +
    Math.cos(deg2rad(lat1)) * Math.cos(deg2rad(lat2)) * 
    Math.sin(dLon/2) * Math.sin(dLon/2);
  var c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a)); 
  return R * c;
}
function deg2rad(deg) { return deg * (Math.PI/180) }
var distance = Math.round(getDistanceFromLatLonInKm(lat, lon, targetLat, targetLon));
var msgDist = { payload: distance, topic: "Distance to Taichung" };

var statusText = vis === "daylight" ? "☀️ 日照區 (DAYLIGHT)" : "🌑 陰影區 (ECLIPSE)";
var statusColor = vis === "daylight" ? "#FF8C00" : "#808080";
var msgVis = { payload: statusText, color: statusColor };

var prevVis = flow.get('prev_visibility') || "";
var msgAlert = null;
var msgToast = null;
if (prevVis !== "" && vis !== prevVis) {
    var text = "";
    if (vis === "daylight") {
        text = "警報：進入日照區。";
        msgToast = { payload: "☀️ 系統: 偵測到日照", color: "orange" };
    } else {
        text = "警報：進入陰影區。";
        msgToast = { payload: "🌑 系統: 偵測到陰影", color: "grey" };
    }
    msgAlert = { payload: text };
}
flow.set('prev_visibility', vis);

return [msgMap, msgVel, msgAlt, msgDist, msgVis, msgAlert, msgToast];

if (msg.statusCode !== 200 || !msg.payload || !msg.payload.people) {

    msg.payload = {
        number: "7 (模擬連線)",
        people: [
            { name: "指揮官薛帕德", craft: "ISS (Sim)" },
            { name: "莎拉·康納", craft: "ISS (Sim)" },
            { name: "艾倫·蕾普莉", craft: "SpaceX Dragon" },
            { name: "馬克·瓦特尼", craft: "Soyuz" },
            { name: "庫柏", craft: "Endurance" },
            { name: "布蘭德博士", craft: "Endurance" },
            { name: "TARS", craft: "Robot Case" }
        ]
    };
}
return msg;

// 初始化
var mode = flow.get('gallery_mode') || 'deep_space';
var auto = flow.get('gallery_auto') || false;

// 處理輸入指令
if (msg.topic === 'mode') {
    mode = msg.payload;
    flow.set('gallery_mode', mode);
    // 切換模式後重置索引並觸發更新
    flow.set('gallery_index_' + mode, 0);
}
else if (msg.topic === 'autoplay') {
    auto = msg.payload;
    flow.set('gallery_auto', auto);
    return null; // 不直接觸發，等待下一次 tick
}
else if (msg.topic === 'auto_tick') {
    if (!auto) return null; // 如果沒開自動，忽略 tick
}
// 'next' 指令會直接往下執行


var deepImages = [
    { t: "創生之柱 (M16)", i: "https://upload.wikimedia.org/wikipedia/commons/thumb/b/b2/Eagle_nebula_pillars.jpg/800px-Eagle_nebula_pillars.jpg", d: "韋伯望遠鏡拍攝的老鷹星雲中心。" },
    { t: "船底座星雲", i: "https://upload.wikimedia.org/wikipedia/commons/thumb/e/e1/Carina_Nebula_by_James_Webb_Space_Telescope.jpg/800px-Carina_Nebula_by_James_Webb_Space_Telescope.jpg", d: "宇宙懸崖：恆星形成區細節。" },
    { t: "韋伯深空視場", i: "https://upload.wikimedia.org/wikipedia/commons/thumb/2/23/Webb%27s_First_Deep_Field.jpg/800px-Webb%27s_First_Deep_Field.jpg", d: "SMACS 0723 星系團，遙遠星系光芒。" },
    { t: "史蒂芬五重奏", i: "https://upload.wikimedia.org/wikipedia/commons/thumb/4/4e/Stephan%27s_Quintet_by_James_Webb_Space_Telescope_NIRCam%2BMIRI_Composite.jpg/800px-Stephan%27s_Quintet_by_James_Webb_Space_Telescope_NIRCam%2BMIRI_Composite.jpg", d: "五個星系的引力之舞。" },
    { t: "狼蛛星雲", i: "https://upload.wikimedia.org/wikipedia/commons/thumb/9/94/Tarantula_Nebula_TRAPPIST.jpg/800px-Tarantula_Nebula_TRAPPIST.jpg", d: "本星系群中最活躍的恆星形成區。" },
    { t: "哈伯深空", i: "https://upload.wikimedia.org/wikipedia/commons/thumb/3/38/Hubble_Ultra_Deep_Field_with_Scale_Bar.jpg/800px-Hubble_Ultra_Deep_Field_with_Scale_Bar.jpg", d: "包含約10,000個星系的深空影像。" },
    { t: "草帽星系 (M104)", i: "https://upload.wikimedia.org/wikipedia/commons/thumb/5/5e/M104_ngc4594_sombrero_galaxy_hi-res.jpg/800px-M104_ngc4594_sombrero_galaxy_hi-res.jpg", d: "位於室女座的螺旋星系。" },
    { t: "蟹狀星雲 (M1)", i: "https://upload.wikimedia.org/wikipedia/commons/thumb/0/00/Crab_Nebula.jpg/800px-Crab_Nebula.jpg", d: "超新星殘骸，脈衝星風星雲。" },
    { t: "渦狀星系 (M51)", i: "https://upload.wikimedia.org/wikipedia/commons/thumb/d/db/Messier51_sRGB.jpg/800px-Messier51_sRGB.jpg", d: "經典的螺旋星系結構。" },
    { t: "仙女座星系 (M31)", i: "https://upload.wikimedia.org/wikipedia/commons/thumb/c/c2/M31_Galaxy.jpg/800px-M31_Galaxy.jpg", d: "距離地球最近的螺旋星系。" },
    { t: "貓眼星雲", i: "https://upload.wikimedia.org/wikipedia/commons/thumb/5/52/Cat%27s_Eye_Nebula_Mosaico.jpg/800px-Cat%27s_Eye_Nebula_Mosaico.jpg", d: "結構最複雜的行星狀星雲之一。" },
    { t: "馬頭星雲", i: "https://upload.wikimedia.org/wikipedia/commons/thumb/6/68/Barnard_33.jpg/800px-Barnard_33.jpg", d: "位於獵戶座的暗星雲。" }
];

var idx = flow.get('gallery_index_deep') || 0;
if (msg.topic === 'next' || msg.topic === 'auto_tick') idx++;
if (idx >= deepImages.length) idx = 0;
flow.set('gallery_index_deep', idx);

var imgData = deepImages[idx];
return [{
    payload: {
        img: imgData.i,
        title: imgData.t,
        desc: imgData.d,
        source: "NASA/ESA/Hubble/Webb"
    }
}, null];

// V8修正：確保資料庫鍵值與下拉選單完全一致
var db = {
    "sun": { name: "太陽 (Sun)", gravity: "274 m/s²", temp: "5505 °C (表面)", mass: "1.989 × 10^30 kg", moons: 0, type: "恆星" },
    "mercury": { name: "水星 (Mercury)", gravity: "3.7 m/s²", temp: "167 °C", mass: "3.285 × 10^23 kg", moons: 0, type: "行星" },
    "venus": { name: "金星 (Venus)", gravity: "8.87 m/s²", temp: "464 °C", mass: "4.867 × 10^24 kg", moons: 0, type: "行星" },
    "earth": { name: "地球 (Earth)", gravity: "9.8 m/s²", temp: "15 °C", mass: "5.972 × 10^24 kg", moons: 1, type: "行星" },
    "mars": { name: "火星 (Mars)", gravity: "3.71 m/s²", temp: "-65 °C", mass: "6.39 × 10^23 kg", moons: 2, type: "行星" },
    "jupiter": { name: "木星 (Jupiter)", gravity: "24.79 m/s²", temp: "-110 °C", mass: "1.898 × 10^27 kg", moons: 79, type: "氣態巨行星" },
    "saturn": { name: "土星 (Saturn)", gravity: "10.44 m/s²", temp: "-140 °C", mass: "5.683 × 10^26 kg", moons: 82, type: "氣態巨行星" },
    "uranus": { name: "天王星 (Uranus)", gravity: "8.69 m/s²", temp: "-195 °C", mass: "8.681 × 10^25 kg", moons: 27, type: "冰巨行星" },
    "neptune": { name: "海王星 (Neptune)", gravity: "11.15 m/s²", temp: "-200 °C", mass: "1.024 × 10^26 kg", moons: 14, type: "冰巨行星" }
};

var selected = msg.payload;
if (db[selected]) {
    msg.payload = db[selected];
} else {
    // 預設或無效值
    msg.payload = { name: "請選擇目標", gravity: "-", temp: "-", mass: "-", moons: "-", type: "-" };
}
return msg;

// Simulate Space Weather Data
var solarWind = Math.floor(Math.random() * (600 - 300 + 1) + 300); // 300-600 km/s
var kpIndex = Math.floor(Math.random() * 9); // 0-9 Kp index
var xRay = "A" + (Math.random() * 9).toFixed(1); // X-Ray Flux
if (Math.random() > 0.8) xRay = "M" + (Math.random() * 5).toFixed(1);

msg.payload = {
    wind: solarWind,
    kp: kpIndex,
    xray: xRay,
    status: kpIndex > 5 ? "磁暴警報" : "一般"
};
return msg;

if (!msg.payload || String(msg.payload).trim() === "") {
    return null; 
}

const API_KEY = "YOUR_API_KEY_HERE";

msg.url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-lite:generateContent?key=${API_KEY}`;

msg.headers = {
    "Content-Type": "application/json"
};

msg.payload = {
    "contents": [{
        "parts": [{
            "text": msg.payload
        }]
    }]
};

return msg;

if (msg.payload && msg.payload.candidates && msg.payload.candidates.length > 0) {
    msg.payload = msg.payload.candidates[0].content.parts[0].text;
    msg.topic = "gemini";
} else {
    msg.payload = "API 錯誤或無內容";
}
return msg;

// 檢查 API 是否回傳了結果
if (msg.payload && msg.payload.results) {
    // 只保留 results 陣列傳給下一個節點
    msg.payload = msg.payload.results;
} else {
    msg.payload = [];
}
return msg;
